    isostaticRoot({elevationKm,crustDensityKgM3,mantleDensityKgM3}) { const h=nonnegative(elevationKm,'Elevation'),rc=positive(crustDensityKgM3,'Crust density'),rm=positive(mantleDensityKgM3,'Mantle density'); if(rm<=rc)throw new Error('Mantle density must exceed crust density.'); return {rootThicknessKm:round(h*rc/(rm-rc))}; },

    barometricPressure({pressure0Pa,tempK,heightM,molarMassKgMol}) { const P0=positive(pressure0Pa,'Reference pressure'),T=positive(tempK,'Temperature'),h=n(heightM),M=positive(molarMassKgMol,'Molar mass'); return {pressurePa:round(P0*Math.exp(-g*M*h/(R*T)))}; },
    hypsometricThickness({pressureLowerHpa,pressureUpperHpa,meanTempK}) { const p1=positive(pressureLowerHpa,'Lower pressure'),p2=positive(pressureUpperHpa,'Upper pressure'),T=positive(meanTempK,'Mean temperature'); if(p1<=p2)throw new Error('Lower-level pressure must exceed upper-level pressure.'); return {thicknessM:round(Rd*T/g*Math.log(p1/p2))}; },
    dryAdiabaticParcel({tempC,heightChangeM}) { return {finalTempC:round(n(tempC)-g/cpAir*n(heightChangeM))}; },
