    potentialTemperature({tempK,pressureHpa,referenceHpa}) { const T=positive(tempK,'Temperature'),p=positive(pressureHpa,'Pressure'),p0=positive(referenceHpa,'Reference pressure'); return {potentialTemperatureK:round(T*Math.pow(p0/p,Rd/cpAir))}; },
    windPowerDensity({airDensityKgM3,windSpeedMs}) { const rho=positive(airDensityKgM3,'Air density'),v=nonnegative(windSpeedMs,'Wind speed'); return {powerDensityWm2:round(0.5*rho*v**3)}; },
    co2RadiativeForcing({initialPpm,finalPpm}) { const c0=positive(initialPpm,'Initial concentration'),c1=positive(finalPpm,'Final concentration'); return {radiativeForcingWm2:round(5.35*Math.log(c1/c0))}; },
