    heatingDegreeDays({meanTempC,baseTempC,days}) { return {heatingDegreeDays:round(Math.max(0,n(baseTempC)-n(meanTempC))*positive(days,'Days'))}; },
    coolingDegreeDays({meanTempC,baseTempC,days}) { return {coolingDegreeDays:round(Math.max(0,n(meanTempC)-n(baseTempC))*positive(days,'Days'))}; },
    climateSensitivity({forcingWm2,sensitivityPerDoublingC}) { return {equilibriumWarmingC:round(n(forcingWm2)*positive(sensitivityPerDoublingC,'Sensitivity')/3.7)}; },
