    carbonBudgetYears({remainingGtCO2,annualGtCO2Yr,annualChangePercent}) { const B=nonnegative(remainingGtCO2,'Remaining budget'),E=positive(annualGtCO2Yr,'Annual emissions'),r=n(annualChangePercent)/100; let years;if(Math.abs(r)<1e-12)years=B/E;else if(r>0)years=Math.log(1+B*r/E)/Math.log(1+r);else{const total=E/(-r);years=B>=total?Infinity:Math.log(1-B*(-r)/E)/Math.log(1+r);}return {yearsRemaining:round(years),pathway:r>0?'growing emissions':r<0?'declining emissions':'constant emissions'}; },
