    gumbelReturnLevel({meanValue,standardDeviation,returnPeriodYr}) { const m=n(meanValue),s=positive(standardDeviation,'Standard deviation'),T=positive(returnPeriodYr,'Return period'); if(T<=1)throw new Error('Return period must exceed one year.'); const beta=s*Math.sqrt(6)/Math.PI,mu=m-gammaEuler*beta,y=-Math.log(-Math.log(1-1/T)); return {returnLevel:round(mu+beta*y),reducedVariate:round(y)}; },
