    eDNADecay({initialConcentration,decayPerDay,days}) { const c0=nonnegative(initialConcentration,'Initial concentration'),k=nonnegative(decayPerDay,'Decay rate'),t=nonnegative(days,'Days'); return {remainingConcentration:round(c0*Math.exp(-k*t)),fractionRemaining:round(Math.exp(-k*t))}; },
