    ndvi({nir,red}) { const a=n(nir),b=n(red),d=a+b;if(!d)throw new Error('NIR + red cannot equal zero.');return {ndvi:round((a-b)/d),classification:(a-b)/d>.5?'dense vegetation':(a-b)/d>.2?'sparse vegetation':(a-b)/d>0?'low vegetation':'non-vegetated or water'}; },
