    evi({nir,red,blue}) { const den=n(nir)+6*n(red)-7.5*n(blue)+1;if(!den)throw new Error('EVI denominator cannot equal zero.');return {evi:round(2.5*(n(nir)-n(red))/den)}; },
    broadbandAlbedo({reflectances,weights}) { const r=list(reflectances),w0=list(weights);if(!r.length||r.length!==w0.length)throw new Error('Reflectances and weights must have matching lengths.');const sw=w0.reduce((s,v)=>s+v,0);if(!sw)throw new Error('Weights must sum to a nonzero value.');return {albedo:round(r.reduce((s,v,i)=>s+v*w0[i],0)/sw)}; },
