    classificationMetrics({truePositive,falsePositive,trueNegative,falseNegative}) { const tp=nonnegative(truePositive,'True positives'),fp=nonnegative(falsePositive,'False positives'),tn=nonnegative(trueNegative,'True negatives'),fn=nonnegative(falseNegative,'False negatives'),N=tp+fp+tn+fn;if(!N)throw new Error('At least one classified sample is required.');const precision=tp/(tp+fp||1),recall=tp/(tp+fn||1);return {accuracy:round((tp+tn)/N),precision:round(precision),recall:round(recall),f1:round(2*precision*recall/(precision+recall||1)),specificity:round(tn/(tn+fp||1))}; },
