    landslideFactorSafety({cohesionKPa,areaM2,weightKN,slopeDeg,porePressureKPa,frictionDeg}) { const A=positive(areaM2,'Area'),W=positive(weightKN,'Weight')*1000,th=n(slopeDeg)*Math.PI/180,u=nonnegative(porePressureKPa,'Pore pressure')*1000,phi=n(frictionDeg)*Math.PI/180;const resisting=nonnegative(cohesionKPa,'Cohesion')*1000*A+(W*Math.cos(th)-u*A)*Math.tan(phi),driving=W*Math.sin(th);if(driving<=0)throw new Error('Driving force must be positive.');const fs=resisting/driving;return {factorOfSafety:round(fs),classification:fs<1?'unstable':fs<1.3?'marginal':'nominally stable'}; },
    ashSettling({particleDiameterUm,particleDensityKgM3,airDensityKgM3,dynamicViscosityPaS}) { const d=positive(particleDiameterUm,'Particle diameter')*1e-6,r=d/2,v=2*(positive(particleDensityKgM3,'Particle density')-positive(airDensityKgM3,'Air density'))*g*r*r/(9*positive(dynamicViscosityPaS,'Dynamic viscosity'));return {stokesSettlingVelocityMS:round(v),_warnings:['Stokes settling is valid only for low particle Reynolds number and spherical particles.']}; },
