    beachRunup({slope,significantWaveHeightM,periodS}) { const L0=g*positive(periodS,'Period')**2/(2*Math.PI),R2=1.1*(0.35*n(slope)*Math.sqrt(positive(significantWaveHeightM,'Wave height')*L0)+Math.sqrt(positive(significantWaveHeightM,'Wave height')*L0*(0.563*n(slope)**2+0.004))/2);return {deepWaterWavelengthM:round(L0),runup2PercentM:round(R2),_warnings:['Empirical runup screening requires a representative beach slope and offshore wave state.']}; },
