    emissionsToPpm({emissionsGtCO2,airborneFraction,gtCO2PerPpm}) { return {concentrationIncreasePpm:round(nonnegative(emissionsGtCO2,'Emissions')*fraction(airborneFraction,'Airborne fraction')/positive(gtCO2PerPpm,'Conversion factor'))}; },
    ecosystemCarbonStock({carbonDensityKgM2,areaKm2}) { const kg=nonnegative(carbonDensityKgM2,'Carbon density')*positive(areaKm2,'Area')*1e6;return {carbonStockT:round(kg/1000),carbonStockGt:round(kg/1e12)}; },
    sequestration({rateTCO2HaYr,areaHa,years}) { return {sequesteredTCO2:round(n(rateTCO2HaYr)*positive(areaHa,'Area')*positive(years,'Years'))}; },
    soilOrganicCarbon({carbonFraction,bulkDensityKgM3,depthM,areaHa,rockFraction}) { const mass=positive(bulkDensityKgM3,'Bulk density')*positive(depthM,'Depth')*positive(areaHa,'Area')*1e4*(1-fraction(rockFraction,'Rock fraction'))*fraction(carbonFraction,'Carbon fraction');return {soilCarbonT:round(mass/1000),soilCO2EquivalentT:round(mass/1000*44/12)}; },
    methaneCO2e({methaneT,gwp}) { return {co2EquivalentT:round(n(methaneT)*positive(gwp,'GWP'))}; },
